#!/usr/bin/env python3
"""Generate the orbit of a base cycle under the det=1 subgroup generated by Tx,Ty,S,T.

Outputs a JSON with canonical cycles.
"""
from __future__ import annotations

import json
from collections import deque
from pathlib import Path
from typing import Dict, List, Tuple


def load_perm_from_map(m: Dict[str, int]) -> Tuple[int, ...]:
    # convert dict keys (strings) to tuple mapping 0..39
    perm = list(range(40))
    for k, v in m.items():
        perm[int(k)] = int(v)
    return tuple(perm)


def compose(p: Tuple[int, ...], q: Tuple[int, ...]) -> Tuple[int, ...]:
    # p o q : apply q then p
    return tuple(p[q[i]] for i in range(len(p)))


def invert(p: Tuple[int, ...]) -> Tuple[int, ...]:
    inv = [0] * len(p)
    for i, v in enumerate(p):
        inv[v] = i
    return tuple(inv)


def cycle_to_canonical(cycle: List[int]) -> Tuple[int, ...]:
    n = len(cycle)
    rots = [tuple(cycle[i:] + cycle[:i]) for i in range(n)]
    rev = list(reversed(cycle))
    rots += [tuple(rev[i:] + rev[:i]) for i in range(n)]
    return min(rots)


def main():
    TXTY = json.loads(Path('analysis/w33_bundle_temp/analysis/W33_Heisenberg_generators_Tx_Ty_Z.json').read_text())
    tx = load_perm_from_map(TXTY['Tx']['perm_40'])
    ty = load_perm_from_map(TXTY['Ty']['perm_40'])

    clif = json.loads(Path('analysis/w33_bundle_temp/analysis/clifford_lift_on_H27_and_N12.json').read_text())
    gens = {}
    for g in clif['generators']:
        name = g['name']
        # create perm_40 by combining perm_H and perm_N12 and setting 0 -> 0
        perm = list(range(40))
        perm[0] = 0
        for k, v in g.get('perm_H', {}).items():
            perm[int(k)] = int(v)
        for k, v in g.get('perm_N12', {}).items():
            perm[int(k)] = int(v)
        gens[name] = tuple(perm)

    S = gens['S']
    T = gens['T']

    # underlying generators for det=1 subgroup
    generators = [tx, ty, S, T]

    # closure
    seen = set()
    q = deque()
    idp = tuple(range(40))
    seen.add(idp)
    q.append(idp)
    while q:
        p = q.popleft()
        for g in generators:
            new = compose(g, p)
            if new not in seen:
                seen.add(new)
                q.append(new)
    print('closure size', len(seen))

    # load base cycle
    cyc_json = json.loads(Path('analysis/minimal_commutator_cycles/minimal_holonomy_cycles_ordered_rootwords.json').read_text(encoding='utf-8'))
    base = list(map(int, cyc_json[0]['cycle_vertices'].split(',')))

    cycles_set = set()
    cycles_list = []
    for perm in seen:
        new_cycle = [perm[i] for i in base]
        can = cycle_to_canonical(new_cycle)
        if can not in cycles_set:
            cycles_set.add(can)
            cycles_list.append({'cycle': list(can)})

    print('unique canonical cycles found', len(cycles_list))
    out = {'closure_size': len(seen), 'canonical_cycles': cycles_list}
    Path('analysis/minimal_commutator_cycles/det1_orbit_cycles.json').write_text(json.dumps(out, indent=2), encoding='utf-8')
    print('Wrote det1_orbit_cycles.json')


if __name__ == '__main__':
    main()
